import { useState } from "react";

const EXTENSION_ID = "jiijdagjdhdenjcdjajagpigpnhldlce";

export default function Summary() {
    const [youtubeId, setYoutubeId] = useState("");

    async function fetchTranscript(videoId) {
        const cleanVideoId = videoId.trim();

        if (!cleanVideoId) {
            console.warn("Please enter a YouTube video ID first.");
            return;
        }

        if (!chrome?.runtime?.sendMessage) {
            console.error("Chrome extension messaging API is not available in this context.");
            return;
        }

        try {
            const result = await chrome.runtime.sendMessage(
                EXTENSION_ID,
                {
                    type: "REQUEST_TRANSCRIPT",
                    videoId: cleanVideoId,
                    autoOpenTab: true,
                }
            );

            console.log(result);
        } catch (error) {
            console.error("Failed to request transcript from Chrome extension.", error);
        }
    }

    return (
        <div className="bg-gray-100 p-4 rounded-md">
            <h2 className="text-xl font-bold mb-2">Summary</h2>

            <input
                type="text"
                value={youtubeId}
                onChange={(e) => setYoutubeId(e.target.value)}
                className="border p-2 rounded"
            />

            <button
                onClick={() => fetchTranscript(youtubeId)}
                className="ml-2 bg-blue-500 text-white px-4 py-2 rounded"
            >
                Enter
            </button>

            <p className="text-gray-700">
                This is a simple summary of the content.
            </p>
        </div>
    );
}